import org.springframework.cache.annotation.EnableCaching;
import org.springframework.context.annotation.*;
import org.springframework.data.redis.cache.*;
import org.springframework.data.redis.connection.RedisConnectionFactory;
import org.springframework.data.redis.serializer.*;
import java.time.Duration;
import java.util.*;

@Configuration
@EnableCaching
public class FlipkartCacheConfig {

    @Bean
    public RedisCacheManager cacheManager(RedisConnectionFactory factory) {
        // JSON serializer (human-readable Redis values):
        var jsonSerializer = new GenericJackson2JsonRedisSerializer();
        var valueSerialization = RedisSerializationContext.SerializationPair
            .fromSerializer(jsonSerializer);

        // Base config with JSON + no null caching:
        var baseConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeValuesWith(valueSerialization)
            .disableCachingNullValues();

        // Per-cache TTL overrides:
        Map<String, RedisCacheConfiguration> configs = new HashMap<>();
        configs.put("products",   baseConfig.entryTtl(Duration.ofMinutes(10)));
        configs.put("prices",     baseConfig.entryTtl(Duration.ofSeconds(30)));
        configs.put("categories", baseConfig.entryTtl(Duration.ofHours(1)));

        return RedisCacheManager.builder(factory)
            .cacheDefaults(baseConfig.entryTtl(Duration.ofMinutes(5)))  // default TTL
            .withInitialCacheConfigurations(configs)
            .build();
    }
}

