import org.springframework.cache.annotation.*;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class ProductService {
    private final ProductRepository repo;
    ProductService(ProductRepository r) { repo = r; }

    // @Caching: group multiple cache operations
    @Caching(evict = {
        @CacheEvict(value = "products",   key = "#id"),
        @CacheEvict(value = "categories", allEntries = true),
        @CacheEvict(value = "search",     allEntries = true)
    })
    @Transactional
    public void deleteProduct(String id) {
        repo.deleteById(id);
        // After this:
        // - 'products::P001' removed from Redis
        // - All 'categories::*' keys removed
        // - All 'search::*' keys removed
        // Next queries for any of these will be cache misses → fresh DB reads
    }

    // Similarly for update — evict specific product + all category/search:
    @Caching(evict = {
        @CacheEvict(value = "products",   key = "#product.id"),
        @CacheEvict(value = "categories", allEntries = true),
        @CacheEvict(value = "search",     allEntries = true)
    })
    @Transactional
    public Product updateProduct(Product product) {
        return repo.save(product);
    }
}

