import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.springframework.beans.factory.annotation.Autowired;

@SpringBootTest
class CacheIntegrationTest {
    @Autowired CityService cityService;
    @SpyBean CityRepository cityRepo;  // Spy: real bean but tracks calls
    @Autowired CacheManager cacheManager;

    @BeforeEach void clearCache() {
        // Clear Redis cache before each test:
        cacheManager.getCacheNames()
            .forEach(name -> cacheManager.getCache(name).clear());
    }

    @Test
    void findById_secondCallHitsCache_notRepository() {
        // First call: cache miss → calls repo
        City first = cityService.findById(1L);
        assertNotNull(first);

        // Second call: cache hit → does NOT call repo again
        City second = cityService.findById(1L);
        assertEquals(first.getId(), second.getId());

        // Verify repo was called exactly ONCE total:
        verify(cityRepo, times(1)).findById(1L);
    }

    @Test
    void afterCacheEvict_repoCalledAgain() {
        cityService.findById(2L);    // call 1: repo hit
        cityService.evictCity(2L);   // evict from cache
        cityService.findById(2L);    // call 2: cache miss again → repo hit

        verify(cityRepo, times(2)).findById(2L);  // called twice!
    }
}

