import org.springframework.cache.annotation.*;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class ConditionalCacheService {
    private final ProductRepository repo;
    ConditionalCacheService(ProductRepository r) { repo = r; }

    // 1. Cache UNLESS result is empty:
    @Cacheable(
        value  = "categories",
        key    = "#category",
        unless = "#result == null || #result.isEmpty()"
        // 'unless' evaluated AFTER method runs: if empty, don't cache
    )
    public List<Product> findByCategory(String category) {
        return repo.findByCategoryIgnoreCase(category);
    }

    // 2. Cache ONLY if id doesn't start with 'TEST-':
    @Cacheable(
        value     = "products",
        key       = "#id",
        condition = "!#id.startsWith('TEST-')"
        // 'condition' evaluated BEFORE method runs: if test ID, skip cache
    )
    public Optional<Product> findById(String id) {
        return repo.findById(id);
    }

    // 3. Cache only for queries of 3+ characters:
    @Cacheable(
        value     = "search",
        key       = "#query.toLowerCase()",
        condition = "#query.length() >= 3"
    )
    public List<Product> searchByName(String query) {
        return repo.findByNameContainingIgnoreCase(query);
    }

    // 4. VIP prices: include userId in key (user-specific pricing)
    // This DOES cache — but per user, not globally:
    @Cacheable(
        value = "vip-prices",
        key   = "'vip:' + #userId + ':' + #productId"
        // key: 'vip:U001:P001' — per user, per product
    )
    public double getVipPrice(String productId, String userId) {
        return pricingService.calculateVipPrice(productId, userId);
    }

    private PricingService pricingService;
    interface PricingService { double calculateVipPrice(String pid, String uid); }
    interface ProductRepository { List<Product> findByCategoryIgnoreCase(String c); Optional<Product> findById(String id); List<Product> findByNameContainingIgnoreCase(String q); }
    record Product(String id, String name, String category) {}
}

