import org.springframework.cache.Cache;
import org.springframework.cache.CacheManager;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import jakarta.annotation.PostConstruct;
import java.util.List;
import java.util.Set;

@Service
public class CacheWarmupService {
    private final CacheManager cacheManager;
    private final RedisTemplate<String, Object> redisTemplate;
    private final CityRepository cityRepo;

    CacheWarmupService(CacheManager cm, RedisTemplate<String,Object> rt, CityRepository cr) {
        cacheManager=cm; redisTemplate=rt; cityRepo=cr;
    }

    // Pre-warm cache on startup — avoids cold-start latency spike:
    @PostConstruct
    public void warmUpCities() {
        System.out.println("[CacheWarmup] Pre-loading top cities into Redis...");
        List<String> topCities = List.of("Mumbai", "Delhi", "Bangalore", "Hyderabad", "Chennai");
        Cache citiesCache = cacheManager.getCache("cities");
        if (citiesCache == null) return;

        for (String city : topCities) {
            // Load from DB and store in cache:
            var restaurants = cityRepo.findByCity(city);
            citiesCache.put(city, restaurants);
            System.out.println("[CacheWarmup] Pre-loaded: " + city + " (" + restaurants.size() + " restaurants)");
        }
        System.out.println("[CacheWarmup] Done. 5 cities pre-loaded.");
    }
    // WHY PRE-WARM?
    // Without warm-up: first users after deploy hit empty cache → all requests go to DB
    //   → spike in DB load → slow first requests → potential timeout
    // With warm-up: cache already populated before traffic arrives
    //   → first users get fast cached responses

    public void manualEvict(String cacheName, Object key) {
        Cache cache = cacheManager.getCache(cacheName);
        if (cache != null) cache.evict(key);
    }

    public long getCacheSize(String cacheName) {
        // Count Redis keys matching the cache prefix:
        Set<String> keys = redisTemplate.keys(cacheName + "::*");
        return keys != null ? keys.size() : 0;
    }

    interface CityRepository {
        List<Object> findByCity(String city);
    }
}

