import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.Map;
import java.util.Optional;

@Service
public class SessionService {
    // Key pattern: 'session:{userId}'
    private static final String SESSION_PREFIX = "session:";
    private static final Duration SESSION_TTL = Duration.ofMinutes(30);

    private final RedisTemplate<String, Object> redisTemplate;

    SessionService(RedisTemplate<String, Object> rt) {
        this.redisTemplate = rt;
    }

    // Save session data with TTL:
    public void saveSession(String userId, Map<String, Object> data) {
        String key = SESSION_PREFIX + userId;  // 'session:U001'
        redisTemplate.opsForValue().set(key, data, SESSION_TTL);
        // Redis: SET session:U001 '{"role":"admin","email":"..."}'  EX 1800
    }

    // Get session (returns null if expired):
    @SuppressWarnings("unchecked")
    public Optional<Map<String, Object>> getSession(String userId) {
        String key = SESSION_PREFIX + userId;
        Object data = redisTemplate.opsForValue().get(key);
        if (data == null) return Optional.empty();
        return Optional.of((Map<String, Object>) data);
    }

    // Extend TTL (reset timer on activity):
    public boolean extendSession(String userId, int extraMinutes) {
        String key = SESSION_PREFIX + userId;
        return Boolean.TRUE.equals(
            redisTemplate.expire(key, Duration.ofMinutes(extraMinutes))
        );
        // Returns false if key doesn't exist (session already expired)
    }

    // Invalidate (logout):
    public void invalidateSession(String userId) {
        redisTemplate.delete(SESSION_PREFIX + userId);
        // DEL session:U001
    }

    // Check if session exists:
    public boolean isSessionActive(String userId) {
        return Boolean.TRUE.equals(
            redisTemplate.hasKey(SESSION_PREFIX + userId)
        );
    }

    // Redis key examples:
    // session:aisha@razorpay.com  → {role: admin, merchantId: M001}
    // session:raj@flipkart.com    → {role: seller, sellerId: S123}
    // TTL: 1800 seconds (30 min); resets on each activity call
}

import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;
import org.springframework.scheduling.annotation.*;
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Autowired;

// application.properties additions:
// spring.cache.redis.enable-statistics=true
// management.endpoints.web.exposure.include=health,metrics,caches
// management.endpoint.caches.enabled=true

@Service
public class CacheMonitorService {
    private final MeterRegistry registry;

    CacheMonitorService(MeterRegistry r) { registry = r; }

    @Scheduled(fixedRate = 60000)  // every minute
    public void logCacheStats() {
        for (String cacheName : java.util.List.of("products", "categories", "search")) {
            double hits   = getCounter(cacheName, "hit");
            double misses = getCounter(cacheName, "miss");
            double total  = hits + misses;

            if (total == 0) continue;
            double hitRate = hits / total * 100;

            System.out.printf("[Cache] %s: hits=%.0f misses=%.0f rate=%.1f%%%n",
                cacheName, hits, misses, hitRate);

            // Alert if products cache hit rate drops:
            if ("products".equals(cacheName) && hitRate < 80) {
                System.err.printf("[Cache ALERT] products hit rate below 80%%: %.1f%%%n", hitRate);
                // In production: send Slack/PagerDuty alert
            }
        }
    }

    private double getCounter(String cacheName, String outcome) {
        try {
            return registry.find("cache.gets")
                .tag("cache", cacheName)
                .tag("cacheManager", "cacheManager")
                .tag("result", outcome)  // 'hit' or 'miss'
                .counter()
                .count();
        } catch (Exception e) {
            return 0;
        }
    }

    // Actuator endpoints:
    // GET /actuator/caches                  → list all caches
    // GET /actuator/metrics/cache.gets      → hit/miss counters
    // GET /actuator/metrics/cache.puts      → entries added
    // GET /actuator/metrics/cache.evictions → entries removed
    // GET /actuator/metrics/cache.size      → current entry count

    public static void main(String[] a) { System.out.println("Cache monitoring active"); }
}

