    public void report(){
        for(String c:List.of("instruments","quotes")){
            try{
                double h=reg.find("cache.gets").tag("cache",c).tag("result","hit").counter().count();
                double m=reg.find("cache.gets").tag("cache",c).tag("result","miss").counter().count();
                if(h+m>0) System.out.printf("[Cache] %s hit=%.1f%%%n",c,h/(h+m)*100);
            }catch(Exception ignored){}
        }
    }
}

